function debounce(fn, delay) {
  let timer;
  return function (...args) {
    clearTimeout(timer);
    timer = setTimeout(() => fn(...args), delay);
  };
}
let calls = 0;
const log = debounce(() => { calls++; }, 20);
log();
log();
log();
setTimeout(() => console.log(calls), 60);

